import { EcsObject, ISingleton } from '../core/EcsObject';
import { UuidMaker } from '../core/EcsUtils';

export const singletonUuidMaker = new UuidMaker();

/**单例基类 */
export abstract class BaseSingleton extends EcsObject implements ISingleton {
    public static isSingleton(param: unknown): param is ISingleton {
        if (!param) return false;
        return param instanceof BaseSingleton;
    }

    /**唯一ID */
    private _uuid = singletonUuidMaker.create();
    public get uuid() {
        return this._uuid;
    }
}